          className={clsx(
            'react-tooltip-arrow',
            coreStyles['arrow'],
            styles['arrow'],
            classNameArrow,
            noArrow && coreStyles['noArrow'],
          )}
          style={arrowStyle}
          ref={tooltipArrowRef}
        />
      </WrapperElement>
    ) : null

  if (!tooltipNode) {
    return null
  }

  if (portalRoot) {
    return createPortal(tooltipNode, portalRoot)
  }

  return tooltipNode
}

export default memo(Tooltip)

